export interface RescuePayload {
  value: number;
  campaignId?: string;
  productCode?: string;
  description: string;
  participantId?: string;
}

export enum RescueStatus {
  IDLE = 'idle',
  LOADING = 'loading',
  SUCCESS = 'success',
  ERROR = 'error',
}

export interface RescueState {
  status: RescueStatus;
  responseStatus?: { message: string };
  error?: string;
}

export interface RescueActions {
  setStatus: (status: RescueStatus) => void;
  setResponseStatus: (responseStatus?: { message: string }) => void;
  setError: (error?: string) => void;
  reset: () => void;
}

export interface RescueApiResponse {
  status: {
    message: string;
  };
  data?: {
    status: string;
  };
}

export type RescueCallbacks = {
  onSuccess?: (status: ResgateResponse['status']) => void;
  onFailed?: (status?: ResgateResponse['status']) => void;
};

