import type { StateCreator } from 'zustand';
import { RescueState, RescueStatus, RescueResponse } from '../models';

export interface RescueActions {
  setStatus: (status: RescueStatus) => void;
  setSuccess: (response: RescueResponse['status']) => void;
  setError: (error?: string) => void;
  reset: () => void;
}

export interface RescueSlice {
  rescue: RescueState;
  rescueActions: RescueActions;
}

const INITIAL_RESCUE_STATE: RescueState = {
  status: RescueStatus.IDLE,
  response: undefined,
  error: undefined,
};

export const createRescueSlice: StateCreator<RescueSlice, [], [], RescueSlice> = (set) => ({
  rescue: INITIAL_RESCUE_STATE,
  rescueActions: {
    setStatus: (status) =>
      set((state) => ({
        rescue: { ...state.rescue, status },
      })),
    setSuccess: (response) =>
      set((state) => ({
        rescue: {
          ...state.rescue,
          status: RescueStatus.SUCCESS,
          response,
          error: undefined,
        },
      })),
    setError: (error) =>
      set((state) => ({
        rescue: {
          ...state.rescue,
          status: RescueStatus.ERROR,
          error,
        },
      })),
    reset: () =>
      set({
        rescue: INITIAL_RESCUE_STATE,
      }),
  },
});

